ipcMain.handle('open-container-logs', (event, name) => {
  // name comes from the renderer
  return new Promise((resolve, reject) => {
    exec(`docker logs ${name}`, (err, stdout) => {
      if (err) return reject(err);
      resolve(stdout);
    });
  });
});

ipcMain.handle('open-container-logs', (event, name) => {
  // validate then pass as an argument array — no shell
  if (typeof name !== 'string' || !/^[A-Za-z0-9_-]+$/.test(name)) {
    throw new Error('invalid container name');
  }
  return new Promise((resolve, reject) => {
    execFile('docker', ['logs', name], (err, stdout) => {
      if (err) return reject(err);
      resolve(stdout);
    });
  });
});

const BASE = app.getPath('userData');
ipcMain.handle('read-note', (event, filePath) => {
  // filePath comes from the renderer
  return fs.promises.readFile(BASE + '/' + filePath, 'utf8');
});

const BASE = app.getPath('userData');
ipcMain.handle('read-note', (event, filePath) => {
  // confine the resolved path inside BASE
  const resolved = path.resolve(BASE, filePath);
  if (!resolved.startsWith(BASE + path.sep)) {
    throw new Error('path escapes base directory');
  }
  return fs.promises.readFile(resolved, 'utf8');
});
